                input.pressure_kpa <= CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                /* First valid pressure seen in band: switch to HOLDING */
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Outside working band: relieving */
                controller->state = CONTROLLER_STATE_RELIEVING;
            }
        }
    }

    /* Handle valid door input */
    if (input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;

        /* Door closed: pressurize if low pressure, vent if high pressure */
        if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            /* Low pressure with door closed: pressurizing */
            controller_state_t prev_state = controller->state;
            if (prev_state == CONTROLLER_STATE_SAFE_VENT || prev_state == CONTROLLER_STATE_HOLDING) {
                controller->state = CONTROLLER_STATE_PRESSURIZING;
            }
        } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            /* High pressure with door closed: relieving */
            controller_state_t prev_state = controller->state;
            if (prev_state == CONTROLLER_STATE_HOLDING) {
                controller->state = CONTROLLER_STATE_RELIEVING;
            }
        } else {
            /* In band with door closed: holding */
            controller_state_t prev_state = controller->state;
            if (prev_state != CONTROLLER_STATE_HOLDING) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }

    /* Handle door open event - forces safe vent-open immediately, 
       regardless of pressure state. This is the key requirement. */

    output.vent_open = true;
    output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
    output.changed = true;

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);

    return output;
}

